-- Create "user_auth_identities" table
CREATE TABLE "user_auth_identities" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "deleted_at" timestamptz NULL,
  "user_id" bigint NOT NULL,
  "provider" character varying NOT NULL,
  "provider_key" character varying NOT NULL,
  "provider_subject_hash" character varying NOT NULL,
  "subject_hint" character varying NOT NULL DEFAULT '',
  "display_name" character varying NOT NULL DEFAULT '',
  "email" character varying NOT NULL DEFAULT '',
  "email_verified" boolean NOT NULL DEFAULT false,
  "avatar_url" character varying NOT NULL DEFAULT '',
  "verified_at" timestamptz NULL,
  "last_used_at" timestamptz NULL,
  PRIMARY KEY ("id")
);
-- Create index "userauthidentity_last_used_at" to table: "user_auth_identities"
CREATE INDEX "userauthidentity_last_used_at" ON "user_auth_identities" ("last_used_at");
-- Create index "userauthidentity_provider_provider_key_provider_subject_hash" to table: "user_auth_identities"
CREATE UNIQUE INDEX "userauthidentity_provider_provider_key_provider_subject_hash" ON "user_auth_identities" ("provider", "provider_key", "provider_subject_hash");
-- Create index "userauthidentity_user_id" to table: "user_auth_identities"
CREATE INDEX "userauthidentity_user_id" ON "user_auth_identities" ("user_id");
-- Create index "userauthidentity_user_id_provider" to table: "user_auth_identities"
CREATE INDEX "userauthidentity_user_id_provider" ON "user_auth_identities" ("user_id", "provider");
